const http = require('http');
const https = require('https');

class Req {
    static get(path, callback, options = {}) {
        if(typeof callback !== 'function')
            throw new TypeError('callback must be a function');
        let get;
        if(path.startsWith('https'))
            get = https.get;
        else if(path.startsWith('http'))
            get = http.get;
        else
            throw new TypeError('path must be a URL');

        if(options.qs) {
            // const qs = [];
            // for(const key in options.qs) {
            //     qs.push(`${key}=${options.qs[key]}`);
            // }
            const qs = Object.keys(options.qs)
                .map(key => `${key}=${options.qs[key]}`);
            path += `?${qs.join('&')}`;
        }

        get(path, res => {
            let body = '';
            res.on('data', chunk => body += chunk);
            res.on('end', () => callback(null, res, body));
            res.on('error', err => callback(err, res, body));
        });
    }
}

module.exports = Req;